### 2. жЁЎеһӢиҺ·еҸ–дјҳе…Ҳзә§ (`model.ts:25-82`)

```typescript
export async function getNovelModel(): Promise<NovelModelResult> {
  // е°қиҜ• 1: д»Һй»ҳи®Ө agent иҺ·еҸ–жЁЎеһӢй…ҚзҪ®
  try {
    const agentName = await Agent.defaultAgent()
    const agent = await Agent.get(agentName)
    if (agent?.model) {
      log.info("using_agent_model", { 
        agent: agentName, 
        model: `${agent.model.providerID}/${agent.model.modelID}` 
      })
      return agent.model
    }
  } catch (error) {
    log.debug("agent_model_unavailable", { error: String(error) })
  }

  // е°қиҜ• 2: д»Һ Provider.defaultModel() иҺ·еҸ–
  try {
    const configured = await Provider.defaultModel()
    // йӘҢиҜҒжЁЎеһӢжҳҜеҗҰзңҹжӯЈеҸҜз”Ё
    await Provider.getModel(configured.providerID, configured.modelID)
    log.info("using_configured_model", { 
      model: `${configured.providerID}/${configured.modelID}` 
    })
    return configured
  } catch (error) {
    log.debug("configured_model_unavailable", { error: String(error) })
  }

  // е°қиҜ• 3: иҺ·еҸ–д»»ж„ҸеҸҜз”Ёзҡ„ provider е’ҢжЁЎеһӢ
  try {
    const providers = await Provider.list()
    const providerEntries = Object.values(providers)

    if (providerEntries.length > 0) {
      // жҹҘжүҫжңүжЁЎеһӢзҡ„з¬¬дёҖдёӘ provider
      for (const provider of providerEntries) {
        const models = Object.values(provider.models)
        if (models.length > 0) {
          // дҪҝз”ЁжҺ’еәҸйҖүжӢ©жңҖдҪіжЁЎеһӢ
          const sorted = Provider.sort(models)
          const selected = sorted[0]
          if (selected) {
            log.info("using_fallback_provider_model", {
              provider: provider.id,
              model: selected.id,
            })
            return {
              providerID: provider.id,
              modelID: selected.id,
            }
          }
        }
      }
    }
  } catch (error) {
    log.debug("fallback_provider_search_failed", { error: String(error) })
  }

  // жүҖжңүе°қиҜ•йғҪеӨұиҙҘ
  throw new Error(
    "No AI model available. Please configure a model in .opencode/opencode.jsonc " +
    "or set up a provider with API keys.",
  )
}
```

